function createZone(
    bytes32 salt
) external override returns (address derivedAddress) {
    // Ensure the caller is the owner.
    if (msg.sender != _owner) {
        revert CallerIsNotOwner();
    }

    // Derive the PausableZone address.
    // This expression demonstrates address computation but is not required.
    derivedAddress = address(
        uint160(
            uint256(
                keccak256(
                    abi.encodePacked(
                        bytes1(0xff),
                        address(this),
                        salt,
                        zoneCreationCode
                    )
                )
            )
        )
    );

    // Revert if a zone is already deployed to the derived address.
    if (derivedAddress.code.length != 0) {
        revert ZoneAlreadyExists(derivedAddress);
    }

    // Deploy the zone using the supplied salt.
    new PausableZone{ salt: salt }();

    // Emit an event signifying that the zone was created.
    emit ZoneCreated(derivedAddress, salt);
}

function _permitTransferFrom(
    PermitBatchTransferFrom memory permit,
    SignatureTransferDetails[] calldata transferDetails,
    address owner,
    bytes32 dataHash,
    bytes calldata signature
) private {
    uint256 numPermitted = permit.permitted.length;

    if (block.timestamp > permit.deadline) revert SignatureExpired(permit.deadline);
    if (numPermitted != transferDetails.length) revert LengthMismatch();

    _useUnorderedNonce(owner, permit.nonce);
    signature.verify(_hashTypedData(dataHash), owner);

    unchecked {
        for (uint256 i = 0; i < numPermitted; ++i) {
            TokenPermissions memory permitted = permit.permitted[i];
            uint256 requestedAmount = transferDetails[i].requestedAmount;

            if (requestedAmount > permitted.amount) revert InvalidAmount(permitted.amount);

            if (requestedAmount != 0) {
                // allow spender to specify which of the permitted tokens should be transferred
                ERC20(permitted.token).safeTransferFrom(owner, transferDetails[i].to, requestedAmount);
            }
        }
    }
}

function binarySearch(
    Observation[65535] storage self,
    uint32 time,
    uint32 target,
    uint16 index,
    uint16 cardinality
) private view returns (Observation memory beforeOrAt, Observation memory atOrAfter) {
    uint256 l = (index + 1) % cardinality; // oldest observation
    uint256 r = l + cardinality - 1; // newest observation
    uint256 i;
    while (true) {
        i = (l + r) / 2;

        beforeOrAt = self[i % cardinality];

        // we've landed on an uninitialized tick, keep searching higher (more recently)
        if (!beforeOrAt.initialized) {
            l = i + 1;
            continue;
        }

        atOrAfter = self[(i + 1) % cardinality];

        bool targetAtOrAfter = lte(time, beforeOrAt.blockTimestamp, target);

        // check if we've found the answer!
        if (targetAtOrAfter && lte(time, target, atOrAfter.blockTimestamp)) break;

        if (!targetAtOrAfter) r = i - 1;
        else l = i + 1;
    }
}

function batchGetLimitOrderRelevantStates(
    LibNativeOrder.LimitOrder[] calldata orders,
    LibSignature.Signature[] calldata signatures
)
    external
    view
    returns (
        LibNativeOrder.OrderInfo[] memory orderInfos,
        uint128[] memory actualFillableTakerTokenAmounts,
        bool[] memory isSignatureValids
    )
{
    require(orders.length == signatures.length, "NativeOrdersFeature/MISMATCHED_ARRAY_LENGTHS");
    orderInfos = new LibNativeOrder.OrderInfo[](orders.length);
    actualFillableTakerTokenAmounts = new uint128[](orders.length);
    isSignatureValids = new bool[](orders.length);
    for (uint256 i = 0; i < orders.length; ++i) {
        try this.getLimitOrderRelevantState(orders[i], signatures[i]) returns (
            LibNativeOrder.OrderInfo memory orderInfo,
            uint128 actualFillableTakerTokenAmount,
            bool isSignatureValid
        ) {
            orderInfos[i] = orderInfo;
            actualFillableTakerTokenAmounts[i] = actualFillableTakerTokenAmount;
            isSignatureValids[i] = isSignatureValid;
        } catch {}
    }
}

