function excessivelySafeCall(
    address _target,
    uint _gas,
    uint16 _maxCopy,
    bytes memory _calldata
) internal returns (bool, bytes memory) {
    // set up for assembly call
    uint _toCopy;
    bool _success;
    bytes memory _returnData = new bytes(_maxCopy);
    // dispatch message to recipient
    // by assembly calling "handle" function
    // we call via assembly to avoid memcopying a very large returndata
    // returned by a malicious contract
    assembly {
        _success := call(
            _gas, // gas
            _target, // recipient
            0, // ether value
            add(_calldata, 0x20), // inloc
            mload(_calldata), // inlen
            0, // outloc
            0 // outlen
        )
        // limit our copy to 256 bytes
        _toCopy := returndatasize()
        if gt(_toCopy, _maxCopy) {
            _toCopy := _maxCopy
        }
        // Store the length of the copied bytes
        mstore(_returnData, _toCopy)
        // copy the bytes from returndata[0:_toCopy]
        returndatacopy(add(_returnData, 0x20), 0, _toCopy)
    }
    return (_success, _returnData);
}

function _setTimelockExpirationPrivate(
  bytes4 functionSelector, uint256 newTimelockExpiration
) private {
  // Ensure that the new timelock expiration will not cause an overflow error.
  require(
    newTimelockExpiration < _A_TRILLION_YEARS,
    "Supplied default timelock expiration is too large."
  );

  // Ensure that the new timelock expiration is not too short.
  require(
    newTimelockExpiration > 1 minutes,
    "New timelock expiration is too short."
  );

  // Get the existing timelock expiration, if any.
  uint256 oldTimelockExpiration = uint256(
    _timelockDefaults[functionSelector].expiration
  );

  // Update the timelock expiration on the provided function.
  _timelockDefaults[functionSelector].expiration = uint128(
    newTimelockExpiration
  );

  // Emit a `TimelockExpirationModified` event with the appropriate arguments.
  emit TimelockExpirationModified(
    functionSelector, oldTimelockExpiration, newTimelockExpiration
  );
}

function setSubnodeRecord(
    bytes32 parentNode,
    string memory label,
    address owner,
    address resolver,
    uint64 ttl,
    uint32 fuses,
    uint64 expiry
) public onlyTokenOwner(parentNode) returns (bytes32 node) {
    bytes32 labelhash = keccak256(bytes(label));
    node = _makeNode(parentNode, labelhash);
    _checkCanCallSetSubnodeOwner(parentNode, node);
    _checkFusesAreSettable(node, fuses);
    _saveLabel(parentNode, node, label);
    expiry = _checkParentFusesAndExpiry(parentNode, node, fuses, expiry);
    if (!_isWrapped(node)) {
        ens.setSubnodeRecord(
            parentNode,
            labelhash,
            address(this),
            resolver,
            ttl
        );
        _storeNameAndWrap(parentNode, node, label, owner, fuses, expiry);
    } else {
        ens.setSubnodeRecord(
            parentNode,
            labelhash,
            address(this),
            resolver,
            ttl
        );
        _updateName(parentNode, node, label, owner, fuses, expiry);
    }
}

function _checkIfMultipleCollectionsAndTokens(
    address[] memory collections,
    uint256[] memory tokenIds,
    uint256 attributesLength
)
    internal
    pure
    returns (
        bool multipleCollections,
        bool multipleTokens,
        bool multipleAttributes,
        uint256 loopLength
    )
{
    multipleCollections = collections.length != 1;
    multipleTokens = tokenIds.length != 1;
    multipleAttributes = attributesLength != 1;
    if (
        (multipleCollections &&
            multipleAttributes &&
            collections.length != attributesLength) ||
        (multipleTokens &&
            multipleAttributes &&
            tokenIds.length != attributesLength) ||
        (multipleCollections &&
            multipleTokens &&
            collections.length != tokenIds.length)
    ) {
        revert LengthsMismatch();
    }

    if (multipleCollections) {
        loopLength = collections.length;
    } else if (multipleTokens) {
        loopLength = tokenIds.length;
    } else {
        loopLength = attributesLength;
    }
}

function setClaimConditions(ClaimCondition calldata _condition, bool _resetClaimEligibility) external override {
    if (!_canSetClaimConditions()) {
        revert DropUnauthorized();
    }

    bytes32 targetConditionId = conditionId;
    uint256 supplyClaimedAlready = claimCondition.supplyClaimed;

    if (_resetClaimEligibility) {
        supplyClaimedAlready = 0;
        targetConditionId = keccak256(abi.encodePacked(_dropMsgSender(), block.number));
    }

    if (supplyClaimedAlready > _condition.maxClaimableSupply) {
        revert DropExceedMaxSupply();
    }

    claimCondition = ClaimCondition({
        startTimestamp: _condition.startTimestamp,
        maxClaimableSupply: _condition.maxClaimableSupply,
        supplyClaimed: supplyClaimedAlready,
        quantityLimitPerWallet: _condition.quantityLimitPerWallet,
        merkleRoot: _condition.merkleRoot,
        pricePerToken: _condition.pricePerToken,
        currency: _condition.currency,
        metadata: _condition.metadata
    });
    conditionId = targetConditionId;

    emit ClaimConditionUpdated(_condition, _resetClaimEligibility);
}

